var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"노르드나빅 왕국 변경.  \\n왕립 국경수비대 관할 남단 산악국경지대.","JPN":"ノルドナビック王国の辺境。\\n王立国境守備隊管轄の南端山岳国境地帯。","ENG":"[[","TWN":"諾爾德萊比王國邊境 \\n皇室國境護衛隊管轄南方山岳國境地區","THA":"อาณาจักรนอร์ดเนวิก\\nชายแดนเทือกเขาทางตอนใต้สุดขององครักษ์หลวงพิทักษ์ชายแดน","VTN":"Vương quốc Nordnavik.\\nVùng núi biên giới cực nam của Cảnh vệ Biên phòng Hoàng gia.","SCN":"诺德纳维克王国边境。\\n皇家边境护卫队管辖的南端山岳边境地区。","DEU":"Das Königreich Nordnavik.\\nDer südlichste Gebirgszug im Zuständigkeitsbereich des Königlichen Grenzschutzes.","FRA":"Royaume de Nordnavik.\\nBordure montagneuse méridionale, placée sous le contrôle des garde-frontières"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"셔우드 외성.  \\n보류 환자 거주 구역.","JPN":"シャーウッド外郭。\\n保留患者の居住区域。","ENG":"[[","TWN":"休烏特外城 \\n保留患者居住區","THA":"เชอร์วูด ปราสาทชั้นนอก\\nพื้นที่สำรองสำหรับผู้ป่วย","VTN":"Bên ngoài lâu đài Sherwood.\\nKhu dành riêng cho bệnh nhân.","SCN":"舍伍德外城，\\n保留患者居住区。","DEU":"Außenburg Sherwood.\\nReserviertes Patientengebiet.","FRA":"Rempart de Sherwood\\nZone de rétention des patients en phase terminale."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"상태는 어떠냐?","JPN":"状態はどうだ？","ENG":"How are things looking?","TWN":"狀態如何？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"침식된 흔적은 없어요. 적어도 겉으로 보기엔.","JPN":"侵食された跡はありません。少なくとも見た目は。","ENG":"No signs of Corruption. Well, at least on the outside.","TWN":"至少表面上看起來沒有遭受侵蝕的跡象。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"간만에 아주 실하네요. 도시에다 팔아도 되겠는데요?","JPN":"久々によく育ちましたね。都市で売ってもよさそうじゃないですか？","ENG":"It's been a long time since we had such good yield. I think we might even be able to sell them in the city.","TWN":"好久沒遇到這麼漂亮的，可以賣到城裡嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"나 참, 환자 구역에서 키운 감자를 누가 사? 돌이나 안 맞으면 다행이지.","JPN":"まったく、患者区域で育てたジャガイモを誰が買うというんじゃ？　石を投げられないだけマシじゃろうて。","ENG":"*Scoff* Who would want to buy potatoes grown here? We'd be lucky to get out of the city unscathed.","TWN":"你也真是的，誰會買病患區出產的馬鈴薯？你是想被石頭砸嗎。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"음? 눈이 내리네요?","JPN":"うむ？　雪が降ってますね。","ENG":"Hmm? It's snowing?","TWN":"嗯？下雪咧？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"그래. 또 어디서 거지 같은 일이 벌어지려나 보구나.","JPN":"ああ。またどこかでくだらんことでも起こりそうじゃな。","ENG":"It is. I guess something terrible is about to happen.","TWN":"是啊，看來又有壞事要發生了。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"침식체가 나타날지도 몰라요. 수비대에 알릴까요?","JPN":"侵食体が現れるかもしれません。守備隊に知らせましょうか？","ENG":"C.O.s might appear. Should I alert the guards?","TWN":"不知道會不會出現侵蝕體，要告訴護衛隊嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"엘라 대장 모르게 와트한테 귀띔만 해 줘.","JPN":"エラ隊長に悟られぬようワットに耳打ちだけしてやれ。","ENG":"Tell Watt, but make sure it doesn't get into Captain Ella's ears.","TWN":"偷偷透露風聲給華特就好，別讓艾拉隊長知道。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"지난번에 화약 때문에 난 상처가 다 낫지도 않았을 텐데. 괜히 또 덧날라.","JPN":"この前火薬のせいで負った傷がまだ治ってないはずじゃ。こじれたら困るからのう。","ENG":"She still hasn't recovered from that wound she got from the gunpowder last time. It will only delay her healing.","TWN":"上次因爲火藥而引發的傷口都還沒好呢，我擔心她又舊疾復發。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"에이, 그래도 명색이 카운터인데 괜찮겠죠.","JPN":"いやぁ、でもカウンターですから大丈夫でしょう。","ENG":"But she's still a Counter. I'm sure she'll be all right.","TWN":"哎唷，她再怎麼說也是個制裁者，應該沒問題吧？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"인석아, 탈나면 어쩌려고? 그 사람 말고 어느 카운터가 우리까지 지켜 주겠냐?","JPN":"このやろ、病気になった時どうするんじゃ。あの人をおいてわしらを守ってくれるカウンターはおらんじゃろう？","ENG":"You brat. What if something bad happened to her? What other Counter do you think is willing to protect us, hmm?","TWN":"你這傢伙，有個什麼萬一的話怎麼辦？你覺得除了她，還有哪個制裁者會保護我們？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"쓸데없는 소리 그만하고 와트나 찾아가.","JPN":"くだらんこと言わんで、ワットのところに行きなさい。","ENG":"Stop your nonsense and go find Watt.","TWN":"廢話少說，快去找華特吧。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"……어?","JPN":"……あ？","ENG":"...Huh?","TWN":"……呃？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"또 왜?","JPN":"またなんじゃ？","ENG":"What now?","TWN":"你又幹嘛？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};